import {MAX_TAPS,PLAY_SECONDS} from '../config.js';
const rnd=(a,b)=>a+Math.random()*(b-a),clamp=(v,a,b)=>Math.max(a,Math.min(b,v));
let wid=1;export class World{w=320;h=568;score=0;taps=0;time=PLAY_SECONDS;combo=0;waves=[];beacons=[];glass=[];particles=[];onHit=()=>{};reset(w,h){this.w=w;this.h=h;this.score=0;this.taps=0;this.time=PLAY_SECONDS;this.combo=0;this.waves=[];this.particles=[];this.glass=[];this.beacons=[];for(let i=0;i<3;i++){const y=[.3,.5,.7][i]*h+(.5-Math.random())*36;this.beacons.push({id:i,x:(i+1)*w/4,y,baseX:(i+1)*w/4,baseY:y,vx:rnd(-8,8),vy:rnd(-8,8),radius:Math.max(13,Math.min(18,w*.045)),flash:0})}for(let i=0;i<4;i++){const x1=rnd(w*.12,w*.88),y1=rnd(h*.2,h*.8);const len=rnd(64,110),a=rnd(-.9,.9),x2=x1+Math.cos(a)*len,y2=y1+Math.sin(a)*len;const nx=-Math.sin(a),ny=Math.cos(a);this.glass.push({id:i,x1,y1,x2,y2,nx,ny})}}tap(x,y){if(this.taps>=MAX_TAPS)return false;this.taps++;this.addWave(x,y,0,'direct');return true}addWave(x,y,ref,kind){this.waves.push({id:wid++,originX:x,originY:y,radius:1,width:9,speed:165,age:0,life:3,reflections:ref,kind,hit:new Set,edges:new Set,glass:new Set});while(this.waves.length>24)this.waves.shift()}step(dt){this.time-=dt;for(const b of this.beacons){b.flash=Math.max(0,b.flash-dt*3);b.x=clamp(b.x+b.vx*dt,b.radius,this.w-b.radius);b.y=clamp(b.y+b.vy*dt,70,this.h-b.radius);if(b.x<=b.radius||b.x>=this.w-b.radius)b.vx*=-1;if(b.y<=70||b.y>=this.h-b.radius)b.vy*=-1}for(let i=this.waves.length-1;i>=0;i--){const e=this.waves[i];e.age+=dt;e.radius+=e.speed*dt;this.reflect(e);for(const b of this.beacons){if(e.hit.has(b.id))continue;const d=Math.hypot(e.originX-b.x,e.originY-b.y);const error=Math.abs(d-e.radius);const band=e.width+b.radius*.35;if(error<=band){e.hit.add(b.id);const base=e.reflections>=2?260:e.kind==='glass'?200:e.kind==='wall'?160:100;const acc=1+Math.max(0,1-error/band)*.45;const mult=acc*(1+Math.min(this.combo,5)*.12);this.combo++;this.score+=Math.round(base*mult);b.flash=1;b.vx+=(b.x-e.originX)/(d||1)*22;b.vy+=(b.y-e.originY)/(d||1)*22;this.burst(b.x,b.y);this.onHit()}}if(e.age>e.life)this.waves.splice(i,1)}for(let i=this.particles.length-1;i>=0;i--){const p=this.particles[i];p.age+=dt;p.x+=p.vx*dt;p.y+=p.vy*dt;if(p.age>p.life)this.particles.splice(i,1)}}reflect(e){if(e.reflections>=2)return;const sides=[['l',-e.originX,e.originY],['r',2*this.w-e.originX,e.originY],['t',e.originX,-e.originY],['b',e.originX,2*this.h-e.originY]];for(const[s,x,y]of sides){const d=s==='l'?e.originX:s==='r'?this.w-e.originX:s==='t'?e.originY:this.h-e.originY;if(e.radius>d&&!e.edges.has(s)){e.edges.add(s);this.addWave(x,y,e.reflections+1,'wall')}}for(const g of this.glass){if(e.glass.has(g.id))continue;const vx=g.x2-g.x1,vy=g.y2-g.y1,len2=vx*vx+vy*vy;const t=clamp(((e.originX-g.x1)*vx+(e.originY-g.y1)*vy)/len2,0,1);const px=g.x1+vx*t,py=g.y1+vy*t,perp=(e.originX-px)*g.nx+(e.originY-py)*g.ny;if(Math.abs(Math.abs(perp)-e.radius)<9){e.glass.add(g.id);this.addWave(e.originX-2*perp*g.nx,e.originY-2*perp*g.ny,e.reflections+1,'glass')}}}burst(x,y){for(let i=0;i<14;i++)this.particles.push({x,y,vx:rnd(-70,70),vy:rnd(-70,70),age:0,life:rnd(.3,.8)});while(this.particles.length>90)this.particles.shift()}}